// Validate and normalize the incoming task contract
const body = $input.first().json.body || $input.first().json;

const required = ['task_id', 'title', 'goal'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

const task = {
  task_id: String(body.task_id),
  title: String(body.title),
  goal: String(body.goal),
  scope_boundaries: Array.isArray(body.scope_boundaries) ? body.scope_boundaries : [],
  files_allowed: Array.isArray(body.files_allowed) ? body.files_allowed : ['**/*'],
  files_forbidden: Array.isArray(body.files_forbidden) ? body.files_forbidden : [],
  critical_systems_risk: Boolean(body.critical_systems_risk),
  expected_output: Array.isArray(body.expected_output) ? body.expected_output : [],
  checks_required: Array.isArray(body.checks_required) ? body.checks_required : ['typecheck'],
  retry_count: Number(body.retry_count) || 0,
  max_retries: 2
};

return [{ json: task }];

// Classify task risk level based on files and flags
const task = $input.first().json;

const CRITICAL_KEYWORDS = [
  'stripe', 'billing', 'auth', 'login', 'session',
  'twilio', 'oauth', 'token', 'rls', 'provisioning',
  'signup', 'deploy', 'migration'
];

let riskLevel = 'low';
let criticalSystemsFlag = task.critical_systems_risk;

// Check files_allowed for critical system patterns
const allFiles = [...task.files_allowed, ...task.scope_boundaries];
const joinedFiles = allFiles.join(' ').toLowerCase();
const goalLower = task.goal.toLowerCase();

for (const keyword of CRITICAL_KEYWORDS) {
  if (joinedFiles.includes(keyword) || goalLower.includes(keyword)) {
    criticalSystemsFlag = true;
    riskLevel = 'high';
    break;
  }
}

// If files_forbidden is empty, that's medium risk (no guardrails set)
if (!criticalSystemsFlag && task.files_forbidden.length === 0) {
  riskLevel = 'medium';
}

return [{ json: {
  ...task,
  classified_risk: riskLevel,
  critical_systems_detected: criticalSystemsFlag,
  branch_name: `ai/task-${task.task_id}`
} }];

// Build the Claude execution prompt from the task contract
const task = $('Classify Task Risk').first().json;

const prompt = `You are executing an autonomous dev-loop task.

TASK: ${task.title}
GOAL: ${task.goal}
BRANCH: ${task.branch_name}
TASK_ID: ${task.task_id}

SCOPE BOUNDARIES:
${task.scope_boundaries.map(s => '- ' + s).join('\n') || '- No specific boundaries set'}

FILES ALLOWED:
${task.files_allowed.map(f => '- ' + f).join('\n')}

FILES FORBIDDEN (DO NOT TOUCH):
${task.files_forbidden.map(f => '- ' + f).join('\n') || '- None specified'}

EXPECTED OUTPUT:
${task.expected_output.map(o => '- ' + o).join('\n') || '- Complete the goal'}

CHECKS REQUIRED:
${task.checks_required.map(c => '- ' + c).join('\n')}

INSTRUCTIONS:
1. Create branch ${task.branch_name} from main
2. Implement the smallest safe change to achieve the goal
3. Run all required checks
4. Return a JSON execution result with these exact fields:
   - task_id: "${task.task_id}"
   - status: "done" | "failed" | "blocked"
   - files_changed: [list of changed files]
   - checks_run: [{name, status: "pass"|"fail"|"not_run", details}]
   - critical_files_touched: [any critical system files modified]
   - summary: what was done
   - open_issues: [unresolved issues]
   - retry_recommended: boolean

Return ONLY the JSON result block wrapped in \`\`\`json ... \`\`\` tags.`;

return [{ json: {
  task,
  claude_prompt: prompt
} }];

// Write prompt to temp file and call claude-exec.sh
const input = $input.first().json;
const fs = require('fs');
const os = require('os');
const path = require('path');
const { execSync } = require('child_process');

const taskId = input.task.task_id;
const prompt = input.claude_prompt;

// Write prompt to a temp file (avoids shell escaping issues)
const tmpDir = os.tmpdir();
const promptFile = path.join(tmpDir, `dev-loop-prompt-${taskId}.txt`);
fs.writeFileSync(promptFile, prompt, 'utf8');

// Determine repo root from REPO_ROOT env or default
const repoRoot = $env.REPO_ROOT || '/opt/autoshop-ai';
const scriptPath = path.join(repoRoot, 'scripts', 'claude-exec.sh');
const timeout = Number($env.CLAUDE_EXEC_TIMEOUT || 300) * 1000; // ms

let stdout = '';
let exitCode = 0;

try {
  stdout = execSync(
    `bash "${scriptPath}" "${promptFile}" "${taskId}"`,
    {
      cwd: repoRoot,
      timeout: timeout + 10000, // buffer above script's own timeout
      env: {
        ...process.env,
        REPO_ROOT: repoRoot,
        CLAUDE_EXEC_TIMEOUT: String($env.CLAUDE_EXEC_TIMEOUT || 300),
        CLAUDE_EXEC_BUDGET: String($env.CLAUDE_EXEC_BUDGET || '1.00')
      },
      encoding: 'utf8',
      stdio: ['pipe', 'pipe', 'pipe']
    }
  );
} catch (err) {
  exitCode = err.status || 1;
  stdout = err.stdout || '';
}

// Clean up temp file
try { fs.unlinkSync(promptFile); } catch(e) {}

// Parse the JSON output from claude-exec.sh
let result;
try {
  result = JSON.parse(stdout.trim());
} catch(e) {
  result = {
    task_id: taskId,
    status: 'failed',
    files_changed: [],
    checks_run: [],
    critical_files_touched: [],
    summary: `claude-exec.sh output was not valid JSON (exit ${exitCode}): ${stdout.substring(0, 500)}`,
    open_issues: ['Execution adapter output parse error'],
    retry_recommended: true
  };
}

return [{ json: result }];

// Collect execution result and build review packet
const exec = $input.first().json;
const task = $('Classify Task Risk').first().json;

// Determine if critical files were touched
const CRITICAL_KEYWORDS = [
  'stripe', 'billing', 'auth', 'login', 'session',
  'twilio', 'oauth', 'token', 'rls', 'provisioning',
  'signup', 'deploy', 'migration'
];

const criticalTouched = (exec.critical_files_touched || []).length > 0 ||
  (exec.files_changed || []).some(f => {
    const lower = f.toLowerCase();
    return CRITICAL_KEYWORDS.some(k => lower.includes(k));
  });

// Check if all checks passed
const allChecks = exec.checks_run || [];
const checksPassed = allChecks.length > 0 && allChecks.every(c => c.status === 'pass');

// Determine goal match
let goalMatch = 'failed';
if (exec.status === 'done' && checksPassed) {
  goalMatch = (exec.open_issues || []).length === 0 ? 'full' : 'partial';
} else if (exec.status === 'done') {
  goalMatch = 'partial';
}

// Determine risk level
let riskLevel = task.classified_risk || 'low';
if (criticalTouched) riskLevel = 'high';

// Determine recommended decision
let decision = 'ESCALATE';
const retryCount = task.retry_count || 0;

if (exec.status === 'done' && goalMatch === 'full' && !criticalTouched && checksPassed && riskLevel !== 'high') {
  decision = 'SAFE_AUTOMERGE';
} else if (exec.status === 'failed' && exec.retry_recommended && retryCount < task.max_retries) {
  decision = 'FIX_AND_RETRY';
} else {
  decision = 'ESCALATE';
}

// Logical gaps
const gaps = [];
if (!checksPassed && allChecks.length > 0) gaps.push('Some checks failed');
if (exec.status !== 'done') gaps.push(`Execution status: ${exec.status}`);
if ((exec.open_issues || []).length > 0) gaps.push(...exec.open_issues);
if (criticalTouched) gaps.push('Critical system files were modified');

const reviewPacket = {
  task_id: exec.task_id,
  review_ready: true,
  goal_match: goalMatch,
  risk_level: riskLevel,
  critical_systems_touched: criticalTouched,
  checks_passed: checksPassed,
  logical_gaps: gaps,
  recommended_decision: decision,
  operator_notes: `Task: ${task.title}. ${exec.summary}`,
  retry_count: retryCount,
  git_diff_summary: exec.files_changed ? exec.files_changed.join(', ') : 'no changes',
  branch: task.branch_name
};

return [{ json: reviewPacket }];

// Retry path: increment counter and re-submit task
const review = $input.first().json;
const task = $('Classify Task Risk').first().json;

const retryTask = {
  ...task,
  retry_count: (task.retry_count || 0) + 1,
  goal: task.goal + ` [RETRY ${(task.retry_count || 0) + 1}: Fix issues: ${review.logical_gaps.join('; ')}]`
};

// Output the retry task — in production, this would loop back
// to the Claude Execution node or re-trigger the webhook
return [{ json: {
  action: 'RETRY',
  retry_count: retryTask.retry_count,
  max_retries: task.max_retries,
  retry_task: retryTask,
  message: `Retry ${retryTask.retry_count}/${task.max_retries} — fixing: ${review.logical_gaps.join('; ')}`
} }];

// Merge gate — DEFAULT OFF
// This node outputs the review packet with merge_allowed flag.
// Actual merge is NOT executed unless AUTOMERGE_ENABLED env var is 'true'.

const review = $('Build Review Packet').first().json;
const automergeEnabled = ($env.AUTOMERGE_ENABLED || 'false').toLowerCase() === 'true';

return [{ json: {
  action: 'SAFE_AUTOMERGE',
  merge_allowed: automergeEnabled,
  merge_executed: false,
  review_packet: review,
  message: automergeEnabled
    ? `Merge gate OPEN — task ${review.task_id} approved for auto-merge on branch ${review.branch}`
    : `Merge gate CLOSED (default) — task ${review.task_id} ready but requires manual merge of ${review.branch}`
} }];

// Escalation path — output for Telegram notification
const review = $('Build Review Packet').first().json;

const telegramMessage = `🚨 DEV-LOOP ESCALATION

Task: ${review.task_id}
Goal Match: ${review.goal_match}
Risk: ${review.risk_level}
Critical Systems: ${review.critical_systems_touched ? 'YES' : 'no'}

Gaps:
${review.logical_gaps.map(g => '• ' + g).join('
') || '(none)'}

Branch: ${review.branch}
Retries: ${review.retry_count}

Action Required: Manual review and decision.`;

return [{ json: {
  action: 'ESCALATE',
  review_packet: review,
  telegram_message: telegramMessage,
  message: `Escalated task ${review.task_id} — requires manual decision`
} }];

// High-risk task — auto-escalate without execution
const task = $('Classify Task Risk').first().json;

const telegramMessage = `🚨 DEV-LOOP: HIGH-RISK TASK BLOCKED\n\nTask: ${task.task_id} — ${task.title}\nRisk: ${task.classified_risk}\nCritical Systems: ${task.critical_systems_detected ? 'YES' : 'no'}\n\nThis task was classified as high-risk and will NOT be auto-executed.\nManual review required before proceeding.`;

const reviewPacket = {
  task_id: task.task_id,
  review_ready: true,
  goal_match: 'failed',
  risk_level: 'high',
  critical_systems_touched: task.critical_systems_detected,
  checks_passed: false,
  logical_gaps: ['Task classified as high-risk — blocked before execution'],
  recommended_decision: 'ESCALATE',
  operator_notes: `High-risk task blocked: ${task.title}. Goal: ${task.goal}`,
  retry_count: 0,
  git_diff_summary: 'no changes — blocked before execution',
  branch: task.branch_name
};

return [{ json: {
  action: 'ESCALATE',
  reason: 'high_risk_blocked',
  review_packet: reviewPacket,
  telegram_message: telegramMessage,
  message: `Task ${task.task_id} blocked — high risk, requires manual approval`
} }];
